sys_script_include.script:
var CoreCompanyAdvancedSearchTableWidgetHelper = Class.create();
CoreCompanyAdvancedSearchTableWidgetHelper.prototype = {
    initialize: function(options) {
        this.transactionId = options.transactionId || gs.generateGUID();
        this.logger = new Logger({
            transactionId: this.transactionId,
            source: "CoreCompanyAdvancedSearchTableWidgetHelper",
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });
    },

    getTableConfigObject: function(params) {
        try {
            return {
                table: "core_company",
                static_query: "nameISNOTEMPTY",
                page_title: "Companies",
                order_by: "name",
                order_direction: "ASC",
                can_save_preferences: "false",
                columns: [{
                        label: "Name",
                        name: "name",
                        default: true
                    },
                    {
                        label: "Street",
                        name: "street",
                        default: true
                    },
                    {
                        label: "City",
                        name: "city",
                        default: true
                    },
                    {
                        label: "Postal code",
                        name: "zip",
                        default: true
                    },
                ],
                can_filter: "false",
            };
        } catch (error) {
            this.logger.error({
                method: "getTableConfigObject",
                error: error.message,
                params: params,
            });
            throw error;
        }
    },

    type: "CoreCompanyAdvancedSearchTableWidgetHelper",
};
